mapper.update:
UPDATE article_column

    sort_order = #{sortOrder},
    update_time = #{updateTime}

WHERE id = #{id}

UPDATE article_column ac INNER JOIN (
SELECT #{item.articleId} AS article_id, #{item.sortOrder} AS sort_order
) temp ON ac.article_id = temp.article_id SET ac.sort_order = temp.sort_order, ac.update_time = NOW() WHERE ac.column_id = #{columnId} AND ac.deleted = 0

mapper.select:
SELECT a.id, a.title
FROM article_column ac
LEFT JOIN article a ON ac.article_id = a.id
WHERE ac.column_id = #{columnId}
  AND ac.deleted = 0
  AND a.deleted = 0
  AND ac.article_id != #{articleId}
  AND ac.sort_order  <  #{sortOrder}
ORDER BY ac.sort_order DESC
LIMIT 1

SELECT a.id, a.title
FROM article_column ac
LEFT JOIN article a ON ac.article_id = a.id
WHERE ac.column_id = #{columnId}
  AND ac.deleted = 0
  AND a.deleted = 0
  AND ac.article_id != #{articleId}
  AND ac.sort_order  >  #{sortOrder}
ORDER BY ac.sort_order ASC
LIMIT 1
